INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24001, 0.0, "アヤネ", 0.0, 401, 24, "2020/07/31 12:00:00", 0.0, 102301, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 2, "2030/12/17 14:59:59", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24002, 2.21, "アヤネ", 0.0, 402, 24, "2020/07/31 12:00:00", 0.0, 102301, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 2, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24003, 0.0, "アヤネ", 0.0, 403, 24, "2020/07/31 12:00:00", 0.0, 102301, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 2, "2030/12/17 14:59:59", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24004, 1.99, "アサヒ", 0.0, 701, 24, "2020/07/31 12:00:00", 0.0, 192201, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 1, "2030/12/17 14:59:59", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24005, 2.21, "アサヒ", 0.0, 702, 24, "2020/07/31 12:00:00", 0.0, 192201, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 2, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24006, 3.33, "アサヒ", 0.0, 703, 24, "2020/07/31 12:00:00", 0.0, 192201, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 1, "2030/12/17 14:59:59", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24007, 0.0, "部員３", 0.0, 801, 24, "2020/07/31 12:00:00", 0.0, 192301, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 2, "2030/12/17 14:59:59", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24008, 2.68, "部員３", 0.0, 802, 24, "2020/07/31 12:00:00", 0.0, 192301, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 2, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24009, 0.0, "部員３", 0.0, 803, 24, "2020/07/31 12:00:00", 0.0, 192301, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 2, "2030/12/17 14:59:59", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24010, 0.0, "", 0.0, 501, 24, "2020/07/31 12:00:00", 0.0, 192501, "やった！", 1, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24011, 0.0, "", 0.0, 502, 24, "2020/07/31 12:00:00", 0.0, 192501, "勝ったよ！", 1, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24012, 0.0, "", 0.0, 503, 24, "2020/07/31 12:00:00", 0.0, 192501, "いい調子！", 1, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24013, 5.33, "ミサト", 0.0, 111, 24, "2020/07/31 12:00:00", 0.0, 113501, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 2, "2030/12/17 14:59:59", 6);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24014, 6.85, "ミサト", 0.0, 112, 24, "2020/07/31 12:00:00", 0.0, 113501, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 2, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24015, 3.0, "ミサト", 0.0, 113, 24, "2020/07/31 12:00:00", 0.0, 113501, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 2, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24016, 6.11, "ダイチ", 0.0, 611, 24, "2020/07/31 12:00:00", 0.0, 192401, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 2, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24017, 6.75, "ダイチ", 0.0, 612, 24, "2020/07/31 12:00:00", 0.0, 192401, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 2, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24018, 0.0, "ダイチ", 0.0, 613, 24, "2020/07/31 12:00:00", 0.0, 192401, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 2, "2030/12/17 14:59:59", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24019, 4.52, "ハツネ", 0.0, 211, 24, "2020/07/31 12:00:00", 0.0, 113401, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 1, "2030/12/17 14:59:59", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24020, 3.89, "ハツネ", 0.0, 212, 24, "2020/07/31 12:00:00", 0.0, 113401, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 1, "2030/12/17 14:59:59", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24021, 13.49, "ハツネ", 0.0, 213, 24, "2020/07/31 12:00:00", 0.0, 113401, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 2, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24022, 3.17, "カヤ", 0.0, 311, 24, "2020/07/31 12:00:00", 0.0, 106501, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 2, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24023, 4.42, "カヤ", 0.0, 312, 24, "2020/07/31 12:00:00", 0.0, 106501, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 2, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24024, 2.89, "カヤ", 0.0, 313, 24, "2020/07/31 12:00:00", 0.0, 106501, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 1, "2030/12/17 14:59:59", 6);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24025, 3.71, "アヤネ", 0.0, 421, 24, "2020/07/31 12:00:00", 0.0, 102301, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 3, "2030/12/17 14:59:59", 4);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24026, 5.1, "アサヒ", 0.0, 721, 24, "2020/07/31 12:00:00", 0.0, 192201, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 1, "2030/12/17 14:59:59", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24027, 4.34, "部員３", 0.0, 821, 24, "2020/07/31 12:00:00", 0.0, 192301, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 3, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24028, 0.0, "", 0.0, 521, 24, "2020/07/31 12:00:00", 0.0, 192501, "いい勝負だったよ\nまたやろうね", 1, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24029, 5.62, "ミサト", 0.0, 101, 24, "2020/07/31 12:00:00", -360.0, 113501, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 2, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24030, 9.58, "ミサト", 0.0, 102, 24, "2020/07/31 12:00:00", -360.0, 113501, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 2, "2030/12/17 14:59:59", 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24031, 0.0, "ミサト", 0.0, 103, 24, "2020/07/31 12:00:00", -360.0, 113501, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 2, "2030/12/17 14:59:59", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24032, 9.13, "ミサト", 0.0, 104, 24, "2020/07/31 12:00:00", -360.0, 113501, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 1, "2030/12/17 14:59:59", 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (10046, 24033, 8.27, "ミサト", 0.0, 105, 24, "2020/07/31 12:00:00", -360.0, 113501, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 2, "2030/12/17 14:59:59", 1);
